$_MODULE['<{PrestashopAPI}prestashop>509a3c36d27ab378b9b6b617d3a034ce'] = 'Keine Unterhaltungen.';
$_MODULE['<{PrestashopAPI}prestashop>ef4b9aee38e1198e272f834d2a67aece'] = 'Der Marktplatz hat geantwortet, aber in einem Format, das dieses Modul nicht erkennt.';
$_MODULE['<{PrestashopAPI}prestashop>60e8b759335732323a38f3ae92983ebc'] = 'Es wurden';
$_MODULE['<{PrestashopAPI}prestashop>8a0bcb4cb387337f6b81a97f1507b37d'] = 'Element(e) zurückgegeben, von denen keines wie eine Unterhaltung aussieht. Mit Ihrem Konto oder API-Schlüssel stimmt nichts nicht: Ihre Produkte und Verkäufe werden normal geladen.';
$_MODULE['<{PrestashopAPI}prestashop>ced8dfb71e1fef4e66506b748517a1b4'] = 'Das ist genau das, was der Marktplatz zurückgesendet hat. Das Kopieren in einen Fehlerbericht reicht aus, um dies zu beheben.';
$_MODULE['<{PrestashopAPI}prestashop>5fb63579fc981698f97d55bfecb213ea'] = 'Kopieren';
$_MODULE['<{PrestashopAPI}prestashop>cd310f329b7e97fd8d3f89709a0f0a34'] = 'Ihre Unterhaltungen konnten nicht heruntergeladen werden.';
$_MODULE['<{PrestashopAPI}prestashop>fc3834f47cae70c79001aebcc1590cb6'] = 'Ihre Produkte und Verkäufe werden normal geladen, daher funktioniert Ihr API-Schlüssel. Verwenden Sie den Hilfe-Reiter, um zu sehen, was der Unterhaltungs-Endpunkt zurückgegeben hat.';
$_MODULE['<{PrestashopAPI}prestashop>90ca6bd42739623112515ff080459cf1'] = 'Hilfe-Reiter öffnen';
$_MODULE['<{PrestashopAPI}prestashop>660f5a7ddd28f0815658dc1f922a054c'] = 'Der Marktplatz hat keine Unterhaltungen für dieses Konto zurückgegeben.';
$_MODULE['<{PrestashopAPI}prestashop>e3b21a23cde5333c6eb4ae77e4910371'] = 'Fügen Sie Ihren API-Schlüssel hinzu, um Ihre Käufernachrichten zu sehen.';
$_MODULE['<{PrestashopAPI}prestashop>93e2f6d89d875ae045742de1d17696e7'] = 'Rechnungen und Auszahlungen';
$_MODULE['<{PrestashopAPI}prestashop>801ab24683a4a8c433c6eb40c48bcd9d'] = 'Herunterladen';
$_MODULE['<{PrestashopAPI}prestashop>d4eb463703a7e5de947f59c53ef36bfa'] = 'Keine Rechnungen vom Marktplatz für diesen Zeitraum zurückgegeben.';
$_MODULE['<{PrestashopAPI}prestashop>1c1325208aa668df5ebd5590d78559b1'] = 'Fügen Sie Ihren API-Schlüssel hinzu, um Ihre Auszahlungen zu sehen.';
$_MODULE['<{PrestashopAPI}prestashop>9cf3cea9fc2559bc3932a1034a8c77bd'] = 'Daten automatisch aktuell halten';
$_MODULE['<{PrestashopAPI}prestashop>70fab415490de4d1c4d958b059ff1cbf'] = 'Das Storefront-Badge und die obigen Zahlen werden aus einer lokalen Kopie Ihrer Marktplatzdaten gelesen, damit kein Besucher Ihres Shops auf den Marktplatz warten muss. Diese Kopie wird aktualisiert, wenn Sie diese Seite öffnen. Um sie stattdessen nach Zeitplan zu aktualisieren, rufen Sie diese URL aus einer Cron-Aufgabe auf, zum Beispiel einmal pro Stunde:';
$_MODULE['<{PrestashopAPI}prestashop>9b4fe89ace5fbb71472cf7a6c3c0ffe9'] = 'Halten Sie diese URL privat: Jeder, der sie hat, kann eine Aktualisierung auslösen. Sie ändert sich, wenn Sie das Modul neu installieren.';
$_MODULE['<{PrestashopAPI}prestashop>850d45fc61bfd3cd575cbc45addd9529'] = 'Zwischengespeicherte Daten';
$_MODULE['<{PrestashopAPI}prestashop>058881da8f789da85e445bfd42bdee3c'] = 'Wenn etwas falsch aussieht, löschen Sie die lokale Kopie und laden Sie alles erneut herunter.';
$_MODULE['<{PrestashopAPI}prestashop>dc034e19f7696e490bc7229a3f70142c'] = 'Zwischengespeicherte Daten löschen';
$_MODULE['<{PrestashopAPI}prestashop>3b488ade6f134eacce53039c0d3b7908'] = 'Wie dieses Modul funktioniert';
$_MODULE['<{PrestashopAPI}prestashop>2b567533f379fab2c398929de7c99c2e'] = 'Woher die Zahlen kommen';
$_MODULE['<{PrestashopAPI}prestashop>1438971d29f373379a0ca6b9e82f04b0'] = 'Marktplatzzahlen werden mit Ihrem eigenen API-Schlüssel von der PrestaShop-Addons-Verkäufer-API heruntergeladen und lokal gespeichert. Ihre Shopzahlen stammen aus Ihren gültigen Bestellungen. Nichts wird woandershin gesendet.';
$_MODULE['<{PrestashopAPI}prestashop>e9ac528d46587d227713f545b102975e'] = 'Warum manche Produkte keine Shopverkäufe zeigen';
$_MODULE['<{PrestashopAPI}prestashop>3585339aed30ba73e0e738d458cff45e'] = 'Das Modul muss wissen, welches Produkt in Ihrem Katalog dasselbe ist wie welches auf dem Marktplatz. Es verknüpft sie, wenn die Referenz Ihres Produkts der Marktplatz-Produkt-ID entspricht. Bei unterschiedlichen Referenzen heften Sie sie manuell im Reiter Produkte an.';
$_MODULE['<{PrestashopAPI}prestashop>53beb26d8bca00f56fbd295fdee83459'] = 'Erstattungen';
$_MODULE['<{PrestashopAPI}prestashop>de980f4d92dea658e437fb1a6db084fd'] = 'Erstattete Einheiten werden auf beiden Seiten von Einheiten und Umsatz abgezogen, sodass die Summen dem entsprechen, was Sie tatsächlich behalten haben.';
$_MODULE['<{PrestashopAPI}prestashop>dfcfc43722eef1eab1e4a12e50a068b1'] = 'Währungen';
$_MODULE['<{PrestashopAPI}prestashop>9bd1ea4499517071a96ee0340edeccf5'] = 'Marktplatzauszahlungen erfolgen meist in Euro, während Ihr Shop in einer anderen Währung verkaufen kann. Kombinierte Summen nutzen Ihren Shop-Wechselkurs. Hat Ihr Shop keinen Kurs für die Marktplatzwährung, werden kombinierte Summen ausgeblendet statt geschätzt.';
$_MODULE['<{PrestashopAPI}prestashop>9635c7ca9186a5b541c68c3e54afc07d'] = 'Das Storefront-Badge';
$_MODULE['<{PrestashopAPI}prestashop>8224e1ccb8232fe6f2ccd4fbeb8c2374'] = 'Optional können Produktseiten in Ihrem eigenen Shop anzeigen, wie oft ein Produkt heruntergeladen wurde, als Social Proof. Es stammt aus der lokalen Kopie Ihrer Daten, kostet keine zusätzliche Ladezeit und blendet sich unter dem von Ihnen gesetzten Schwellenwert aus.';
$_MODULE['<{PrestashopAPI}prestashop>44877c6aa8e93fa5a91c9361211464fb'] = 'Geschwindigkeit';
$_MODULE['<{PrestashopAPI}prestashop>803e2b0d8f5afc76e2e54fad606490c0'] = 'Ein breiter Berichtszeitraum bedeutet mehr Zeilen zum Herunterladen. Fühlt sich die Aktualisierung langsam an, verengen Sie den Zeitraum oder verlängern Sie das Aktualisierungsintervall in den Einstellungen.';
$_MODULE['<{PrestashopAPI}prestashop>8b9c1abd043bde61211bc6d58be58370'] = 'Wenn etwas nicht funktioniert';
$_MODULE['<{PrestashopAPI}prestashop>f2cb075d74e523731af10acbb1177695'] = 'Ihr Server konnte keine ausgehende HTTPS-Verbindung zum Marktplatz öffnen. Shared Hosting blockiert dies oft. Die Statusliste im Dashboard-Reiter zeigt, ob cURL verfügbar ist; wenn ja, fragen Sie Ihren Host, ob ausgehende Verbindungen zu api.addons.prestashop.com erlaubt sind.';
$_MODULE['<{PrestashopAPI}prestashop>f64dc4589dc99c8b6633332d2cd64673'] = 'Erzeugen Sie einen neuen Schlüssel in Ihrem Verkäuferkonto unter Einstellungen dann API, und fügen Sie ihn erneut ein. Kopieren Sie nur den Schlüssel, nicht den umgebenden Text.';
$_MODULE['<{PrestashopAPI}prestashop>e42e9d958504c5158fe91c5d56ee6214'] = 'Die Zahlen sind älter als sie sein sollten';
$_MODULE['<{PrestashopAPI}prestashop>cce5ffc741270470dec823a4fff75552'] = 'Shopverkäufe sind für jedes Produkt null';
$_MODULE['<{PrestashopAPI}prestashop>95dab330ce5b2c1d94467c07916fea17'] = 'Keines Ihrer Marktplatzprodukte wurde mit einem Produkt in Ihrem Katalog verknüpft. Prüfen Sie die Statusliste im Dashboard-Reiter und heften Sie die Produkte manuell im Reiter Produkte an.';
$_MODULE['<{PrestashopAPI}prestashop>e67411c887a32a48389e48e21d409fca'] = 'Was die API zurückgibt';
$_MODULE['<{PrestashopAPI}prestashop>9d0b331fa4855d2fc2b8ffca416cc545'] = 'Der Marktplatz dokumentiert nur seine Produkte und Verkaufsdaten. Alles andere, einschließlich Unterhaltungen, Rechnungen und Auszahlungen, wird aus Feldern gelesen, deren Namen wir ableiten mussten. Dies zeigt eine echte Zeile von jedem Endpunkt Ihres eigenen Kontos, damit das Modul an das angepasst werden kann, was Ihr Konto tatsächlich sendet.';
$_MODULE['<{PrestashopAPI}prestashop>8c97b6869b7a8ca6c4d6ec89ea13cbe0'] = 'Dies sind Live-Daten aus Ihrem Verkäuferkonto und können Käufernamen oder E-Mail-Adressen enthalten. Entfernen Sie persönliche Angaben, bevor Sie sie teilen.';
$_MODULE['<{PrestashopAPI}prestashop>1ad29d73a1351f6885ba5f406942f35c'] = 'Eine Beispielzeile von jedem Endpunkt anzeigen';
$_MODULE['<{PrestashopAPI}prestashop>8f7f4c1ce7a4f933663d10543562b096'] = 'Über';
$_MODULE['<{PrestashopAPI}prestashop>ddad714ca961f9e4b44ca12829085a78'] = 'Seller Dashboard von';
$_MODULE['<{PrestashopAPI}prestashop>2af72f100c356273d46284f6fd1dfc08'] = 'Version';
$_MODULE['<{PrestashopAPI}prestashop>81e8c74ab2339c9b2ea8fe9c17bc3547'] = 'Dieses Modul ist nicht mit PrestaShop SA verbunden oder von ihr empfohlen. Es nutzt die öffentliche Verkäufer-API mit dem von Ihnen bereitgestellten Schlüssel.';
$_MODULE['<{PrestashopAPI}prestashop>a6addb0c07df70c8d878073ac09e7b24'] = '1 Marktplatz-Unterhaltung wartet auf Sie';
